dtsPropsFor.Nav:
/** Active section key: 'dream' (the live dream), 'new', 'library', 'stash', or 'settings'. */
active: string;
/** When true, the live dream leads the nav as its own item with an "up" dot. */
hasDream: boolean;
/** Display name of the live dream; falls back to "Current dream". */
dreamName?: string | null;
/** Called with the chosen section key when the user navigates. */
onNavigate: (v: string) => void;

dtsPropsFor.EngineToggle:
/** The i2v backend selection. The control renders nothing when this is absent or has no options. */
engine?: {
  /** Active engine id, e.g. "wan" or "10eros". */
  active: string;
  /** Selectable engine ids. */
  options: string[];
};

dtsPropsFor.ReadyChip:
/** Live readiness of the dreaming pipeline. */
r: {
  /** Graphics turn-taking (GPU coordinator) is up. */
  coordinator: boolean;
  /** Video generator (ComfyUI) is up. */
  comfyui: boolean;
  /** Story-suggestion model (Ollama) is up. */
  ollama: boolean;
  /** All required pieces are up and Lucid can dream. */
  can_dream: boolean;
  /** Human-readable reasons dreaming is paused (empty when ready). */
  why: string[];
};

dtsPropsFor.ReadinessCard:
/** Live readiness of the dreaming pipeline. When can_dream is false, the card explains which piece is missing. */
r: {
  coordinator: boolean;
  comfyui: boolean;
  ollama: boolean;
  can_dream: boolean;
  why: string[];
};

dtsPropsFor.PrivateCard:
/** Encrypted private-stash status; drives whether the card offers "Save to stash" or a create/unlock prompt. */
stash?: {
  exists: boolean;
  unlocked: boolean;
  /** Stash id this dream is currently saved as, if any (offers "Update" vs "Save"). */
  saved_id?: string | null;
};
/** Navigate to the Stash section to create or unlock the encrypted stash. */
onGoStash?: () => void;

dtsPropsFor.StashPanel:
/** Initial stash status; the panel also reads live status itself. */
stash?: {
  exists: boolean;
  unlocked: boolean;
  saved_id?: string | null;
};
/** Called after a sealed dream is opened (the parent returns to the dream view). */
onOpened?: () => void;
